def _ssrs_data_set_to_nested(ssrs_data_set: SSRSDataSet) -> SSRSDataSetNested:
    """Convert flat SSRSDataSet to nested format."""
    attrs = SSRSDataSetAttributes()
    _populate_ssrs_data_set_attrs(attrs, ssrs_data_set)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        ssrs_data_set, _SSRS_DATA_SET_REL_FIELDS, SSRSDataSetRelationshipAttributes
    )
    return SSRSDataSetNested(
        guid=ssrs_data_set.guid,
        type_name=ssrs_data_set.type_name,
        status=ssrs_data_set.status,
        version=ssrs_data_set.version,
        create_time=ssrs_data_set.create_time,
        update_time=ssrs_data_set.update_time,
        created_by=ssrs_data_set.created_by,
        updated_by=ssrs_data_set.updated_by,
        classifications=ssrs_data_set.classifications,
        classification_names=ssrs_data_set.classification_names,
        meanings=ssrs_data_set.meanings,
        labels=ssrs_data_set.labels,
        business_attributes=ssrs_data_set.business_attributes,
        custom_attributes=ssrs_data_set.custom_attributes,
        pending_tasks=ssrs_data_set.pending_tasks,
        proxy=ssrs_data_set.proxy,
        is_incomplete=ssrs_data_set.is_incomplete,
        provenance_type=ssrs_data_set.provenance_type,
        home_id=ssrs_data_set.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )

def _ssrs_data_set_from_nested(nested: SSRSDataSetNested) -> SSRSDataSet:
    """Convert nested format to flat SSRSDataSet."""
    attrs = nested.attributes if nested.attributes is not UNSET else SSRSDataSetAttributes()
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _SSRS_DATA_SET_REL_FIELDS,
        SSRSDataSetRelationshipAttributes
    )
    return SSRSDataSet(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_ssrs_data_set_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )

def _ssrs_data_set_to_nested_bytes(ssrs_data_set: SSRSDataSet, serde: Serde) -> bytes:
    """Convert flat SSRSDataSet to nested JSON bytes."""
    return serde.encode(_ssrs_data_set_to_nested(ssrs_data_set))


def _ssrs_data_set_from_nested_bytes(data: bytes, serde: Serde) -> SSRSDataSet:
    """Convert nested JSON bytes to flat SSRSDataSet."""
    nested = serde.decode(data, SSRSDataSetNested)
    return _ssrs_data_set_from_nested(nested)

